var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"자신의 운명을 멈추기 위해서... 나뭇가지를 전부 꺾기로 했다고?","JPN":"自分の運命を止めるために……枝を全部落とすことにしたって？","ENG":"To stop her own fate... she decided to break every branch?","TWN":"為了停止自己的命運……所以她決定折斷所有樹枝？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그게 뭘 의미하는지 알고서도 그런 결정을 했다는 거야?","JPN":"それが何を意味してるのか分かってるのに、決断したっていうの？","ENG":"And she made that decision knowing exactly what it meant?","TWN":"她明知道那意味著什麼，還做出這樣的決定？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 의미는 모든 세계의 종말이죠.","JPN":"その意味とは、すべての世界の終末でしょう。","ENG":"It means the end of every world.","TWN":"那意味著所有世界的終結。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이미 수많은 세계가 그렇게, 타기리온의 손에 의해 사라져왔어요.","JPN":"すでに数多くの世界がそうして、タギリオンの手によって消えました。","ENG":"Already, countless worlds have disappeared by Thagirion's hand.","TWN":"已經有無數世界，被塔基里翁親手毀滅。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이해라는 잣대를 들이밀기엔, 이미 너무 멀리 와버렸죠.","JPN":"理解というものさしを突きつけるには、あまりにも遠くに来てしまったんです。","ENG":"We've come far too far to judge it by the standard of understanding.","TWN":"事到如今，再用理解去衡量已經太遲了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"세상을 멸망시킬 이유가 고작 그게 전부라면... 죽은 황금나무를 되살렸어야 할 이유가 있나?","JPN":"世界を滅亡させる理由がたったそれだけなら……死んだ黄金の木を生き返らせる必要なんかある？","ENG":"If that's the only reason to destroy the world... then why bother reviving the dead Golden Tree?","TWN":"如果毀滅世界的理由只有這個……那為什麼還要復活已經死去的黃金樹？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...가능성.","JPN":"……可能性。","ENG":"...Possibilities.","TWN":"……可能性。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"황금나무를 이용해 다른 세상의 가능성을 모으고 그걸 이용하려는 것이라 생각되옵니다.","JPN":"黄金の木を利用して別の世界の可能性を集め、それを利用しようとしているのだと思います。","ENG":"I believe she intends to gather the possibilities of other worlds through the Golden Tree and use them.","TWN":"我認為她想利用黃金樹收集其他世界的可能性，再加以利用。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"제 말이 틀리다면... 부디 반박해주셔요.","JPN":"私が間違っているのなら……反論してください。","ENG":"If I am mistaken... please correct me.","TWN":"如果我說錯了……請反駁我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신은 틀리지 않았어요, 에클레시아.","JPN":"あなたは間違っていませんよ、エクレシア。","ENG":"You're not wrong, Ecclesia.","TWN":"你沒有說錯，艾可露西亞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원이 만들어진 목적은 마왕 타기리온이 부순 세계에 남겨진 가능성을 수집하기 위한 것.","JPN":"楽園が作られた目的は、魔王タギリオンが壊した世界に残された可能性を集めること。","ENG":"The purpose of the Promised Land is to collect the possibilities left behind in the worlds destroyed by the Demon Lord Thagirion.","TWN":"這個樂園被創造出來的目的，就是為了收集那些被魔王塔基里翁毀滅的世界中殘留下來的可能性。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고 이 장소는 멸망한 세계의 터전 위에, 오롯이 제 의지로 세워졌죠.","JPN":"そしてこの場所は、滅亡した世界を土台に純粋に私の意志だけで作りました。","ENG":"And this place was built entirely by my own will, upon the ruins of a ruined world.","TWN":"而這裡建立在已經毀滅的世界，完全出於我的意志而誕生。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그렇다면 어째서 낙원이란 이름을 붙이고 사람들의 소망을 이뤄주는 것입니까?","JPN":"それならどうして楽園という名前をつけ、人々の願いを叶えてくれるのですか？","ENG":"Then why call it the Promised Land and grant the people's wishes?","TWN":"既然如此，為什麼要把它稱為樂園、實現人的願望？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"왜 다른 누군가의 가능성을 짓밟아가면서까지... 주민들에게 희망을 주는 것이냔 말입니다.","JPN":"どうして他の誰かの可能性を踏みにじってまで……住民に希望を与えているのかというのです。","ENG":"Why give hope to the residents... while trampling the possibilities of other worlds?","TWN":"為什麼要踐踏其他人的可能性……卻又給居民帶來希望？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"진실과 행복은 같은 하나의 빛처럼 보이지만, 실은 전혀 어울리지 않는 한 쌍이죠.","JPN":"真実と幸せは同じ一筋の光のように見えますが、実はまったく相入れない一対なのです。","ENG":"Truth and happiness appear to shine like the same light, but in truth they are a pair that cannot coexist.","TWN":"真相與幸福看起來像是同一道光，但其實完全不相容的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신이 진실에 관심을 갖지 않았다면 지금까지도 이 낙원에서 행복을 누리고 있었을 테지만...","JPN":"あなたが真実に目を向けることがなかったなら、今もこの楽園で幸せに暮らしていたはずですが……","ENG":"If you had not taken interest in the truth, you would still be enjoying happiness in this Promised Land even now...","TWN":"如果你沒有對真相產生興趣，你至今依然能在這個樂園享受幸福……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"진실을 알게 된 이젠, 이전의 행복하던 시절로 돌아갈 수 없겠네요.","JPN":"真実を知った今は、もう幸せだった頃には戻れませんね。","ENG":"But now that you know the truth, you can no longer return to the happiness you once had.","TWN":"但現在既然知道了真相，就再也回不到以前那段幸福的日子了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"단 한 순간도...!","JPN":"一瞬でも……！","ENG":"Not for a single moment...!","TWN":"哪怕是一瞬間……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"희생을 필요로 하는 행복 같은 건, 원치 않았사옵니다.","JPN":"犠牲を必要とする幸せなど、望んだことはございません。","ENG":"I never wished for a happiness that requires sacrifice.","TWN":"我不想要需要犧牲的幸福。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"정말로 그렇게 믿나요?","JPN":"本当にそう信じているんですか？","ENG":"Do you truly believe that?","TWN":"你真的這麼相信嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"누구의 희생도 없이 행복을 쟁취할 수 있다고?","JPN":"誰かの犠牲なく、幸せを勝ち取ることができると？","ENG":"That happiness can be obtained without anyone's sacrifice?","TWN":"相信可以在沒有任何人犧牲的情況下獲得幸福？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그야 당연히...!","JPN":"それはもちろん……！","ENG":"Of course I–!","TWN":"那是當然的……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...당연히...","JPN":"……もちろん……","ENG":"...Of course...","TWN":"……當然……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"우리의 조율은 세계의 종말을 막기 위한 수단입니다.","JPN":"私たちの調律は、世界の終末を止めるための手段です。","ENG":"Our tuning is our way to stop the apocalypse.","TWN":"我們的調和是阻止世界末日的手段。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그래서... 사람들을 멋대로 희생시킨 건가요?","JPN":"だから……勝手に人々を犠牲にしたんですか？","ENG":"Is that why... you sacrificed people against their will?","TWN":"所以你……任意地犧牲了別人？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"세상을 구하려고... 제 언니를 그렇게 만든 건가요?","JPN":"世界を救うため……私のお姉さんをこんな姿にしたんですか？","ENG":"Did you do that to my sister too...? To save the world?","TWN":"為了拯救世界……對我姊姊做了那種事？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"다음 악장을 위해 끊어진 현을 갈아야 하듯, 실험에도 항상 새로운 자원이 필요합니다.","JPN":"次の楽章のために切れた弦を取り替えるように、実験にも常に新しい資源が必要です。","ENG":"A broken string must be replaced for the next movement, much like how experiments require new resources.","TWN":"要展開下一個樂章，就必須先換掉斷掉的弦，實驗也是需要新的資源的。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께서도 모든 사실을 알고 계시지만, 이를 묵인하고 계신 걸요.","JPN":"猊下はすべての事実を知りながらも、これを黙認なさっているのです。","ENG":"Her Eminence is aware of all of this, but she has done nothing to stop us.","TWN":"主教也知道這一切，但是她默許了。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...윽.","JPN":"……くっ。","ENG":"...Ngh.","TWN":"……唔。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"방금 그 장면은...?","JPN":"今の光景は……？","ENG":"That scene just now...?","TWN":"剛才那個畫面是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"여기 있었구나, 아우드라.","JPN":"ここにいたのか、アウドラ。","ENG":"So this is where you were, Audra.","TWN":"原來你在這裡啊，奧德拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...오셨네요.","JPN":"……来ましたね。","ENG":"...You've come.","TWN":"……你來了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"기다리고 있었어요.","JPN":"待っていました。","ENG":"I've been waiting.","TWN":"我一直在等你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저게 바로...","JPN":"あれこそが……","ENG":"This is...","TWN":"那個就是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"낙원은 모두의 소망을 이루어주지.","JPN":"楽園はみんなの願いを叶えてくれる。","ENG":"The Promised Land grants everyone's wishes.","TWN":"樂園會實現所有人的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"네가 본 것 역시, 그 아이의 소망이다.","JPN":"お前が見たのもまた、あの子の願いだ。","ENG":"What you saw was also that child's wish.","TWN":"你看到的，也是那孩子的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...아우드라가 바라는, 소망.","JPN":"……アウドラの望む、願い。","ENG":"...Audra's wish.","TWN":"……奧德拉期望的願望。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"이렇게 할 수 밖에 없는 나를, 원망하거라.","JPN":"こうするしかない我を、恨むといい。","ENG":"Resent me, for being left with no choice but this.","TWN":"怨恨只能這麼做的我吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"원망하지 않아요.","JPN":"恨んだりしません。","ENG":"I don't resent you.","TWN":"我不恨你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언제까지나.","JPN":"これからもずっと。","ENG":"Not now. Not ever.","TWN":"永遠不會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...멈춰!!","JPN":"……待って！！","ENG":"...Stop!!","TWN":"……住手！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그대들은 누구지?","JPN":"そなたらは何者だ？","ENG":"Who are you?","TWN":"你們是什麼人？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이럴 수가...","JPN":"そんな……","ENG":"This can't be...","TWN":"怎麼可能……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"검 한 자루로, 이걸 막아낸다고?","JPN":"剣一本で、こちらの攻撃を防いだ？","ENG":"You blocked that with a single sword?","TWN":"只用一把劍，就擋下了這一擊？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"답해라. 그대들은 누구이고, 왜 나를 방해하는 것인가.","JPN":"答えろ。そなたらは何者で、なぜ我の邪魔をするのか。","ENG":"Answer me. Who are you, and why do you interfere with me?","TWN":"回答我。你們是誰，為什麼要妨礙我？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"눈앞의 살생을 막으려 함은, 당연한 일이옵니다.","JPN":"目の前の殺生を止めることは、当たり前のことでございます。","ENG":"Stopping the killing before my eyes is only natural.","TWN":"阻止眼前的殺戮，本就是理所當然之事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그녀를 살려두면 세계는 파국으로 치닫게 된다.","JPN":"彼女を生かしておけば、世界は破局を迎えることになる。","ENG":"If she lives, the world will fall into ruin.","TWN":"若讓她活下去，世界將走向毀滅。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"불씨를 쥔 이가 숲으로 들어가려는 것을 방관하는 것은 죄악과 다름이 없으니.","JPN":"火種を持つ者が森に入るのを傍観することは、罪悪に等しい。","ENG":"To allow one holding a spark to walk into the forest is no different from committing a sin.","TWN":"眼看著手握火種的人走進森林而置之不理，與罪惡無異。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"하나의 살생으로 수많은 죽음을 막을 수 있다고 해도, 나를 막을 셈인가?","JPN":"一の殺生で千の死を阻止できるとしても、我を止めるのか？","ENG":"Even if killing one could prevent countless deaths, will you still stop me?","TWN":"就算一次殺戮就能阻止無數死亡，你們也要阻止我嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그렇다면 살생을 방관하는 것 또한 죄악일 테니.","JPN":"殺生を傍観することもまた罪悪のはずです。","ENG":"Then standing by and allowing a killing would also be a sin.","TWN":"那麼，對殺戮視而不見，同樣也是罪惡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"무슨 말을 하시어도 제 답은 같사옵니다.","JPN":"何をおっしゃってもわたくしの答えは変わりません。","ENG":"No matter what you say, my answer will remain the same.","TWN":"無論怎麼說，我的回答都不會改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"그렇다면 너는, 나의 적이로군.","JPN":"ならばそなたは、我の敵だ。","ENG":"Then you are my enemy.","TWN":"那麼，你就是我的敵人了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_32"},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그래. 당연하게도, 저 둘 사이에 대화 같은 게 통할 리 없나.","JPN":"……そうね。当然ながら、あの二人の間に話が通じるわけがないよね。","ENG":"...Right. Of course there's no way those two could ever talk this out.","TWN":"……也是。他們兩個，本來就不可能有共識。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"덤벼!","JPN":"かかってこい！","ENG":"Come on!","TWN":"來吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};